import sys

class MongoDBAdvancedFilter:
    def __init__(self, connection_string, database_name):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
    
    def execute_where_query(self, collection_name, filter_expression):
        try:
            collection = self.db[collection_name]
            results = list(collection.find({"$where": filter_expression}))
            return results
        except Exception as e:
            raise Exception(f"Query execution failed: {str(e)}")
    
    def execute_where_query_with_params(self, collection_name, filter_expression, params=None):
        try:
            collection = self.db[collection_name]
            if params:
                # Replace parameters in the filter expression
                for key, value in params.items():
                    filter_expression = filter_expression.replace(f"${key}", str(value))
            results = list(collection.find({"$where": filter_expression}))
            return results
        except Exception as e:
            raise Exception(f"Query execution failed: {str(e)}")
    
    def execute_complex_where_query(self, collection_name, filter_expression, sort_field=None, limit_count=None):
        try:
            collection = self.db[collection_name]
            query = {"$where": filter_expression}
            cursor = collection.find(query)
            
            if sort_field:
                cursor = cursor.sort(sort_field)
            
            if limit_count:
                cursor = cursor.limit(limit_count)
            
            results = list(cursor)
            return results
        except Exception as e:
            raise Exception(f"Complex query execution failed: {str(e)}")
    
    def get_collection_info(self, collection_name):
        try:
            collection = self.db[collection_name]
            count = collection.count_documents({})
            return {"collection": collection_name, "document_count": count}
        except Exception as e:
            raise Exception(f"Failed to get collection info: {str(e)}")
    
    def close_connection(self):
        self.client.close()

